.darma-loader-uiverse-purple-pulse-batons__container {
display: flex;
align-items: center;
justify-content: center;
width: 3.75em; /* 60px */
}

.darma-loader-uiverse-purple-pulse-batons__dot {
height: 0.8125em; /* 13px */
width: 1.25em; /* 20px */
margin-right: 0.625em; /* 10px */
border-radius: 0.625em; /* 10px */
background-color: #721a8f;
animation: darma-loader-uiverse-purple-pulse-batons-loaderpulse 1.5s infinite ease-in-out;
}

.darma-loader-uiverse-purple-pulse-batons__dot:last-child {
margin-right: 0;
}

.darma-loader-uiverse-purple-pulse-batons__dot:nth-child(1) {
animation-delay: -0.1875s; /* -0.3s */
}

.darma-loader-uiverse-purple-pulse-batons__dot:nth-child(2) {
animation-delay: -0.0625s; /* -0.1s */
}

.darma-loader-uiverse-purple-pulse-batons__dot:nth-child(3) {
animation-delay: 0.0625s; /* 0.1s */
}

@keyframes darma-loader-uiverse-purple-pulse-batons-loaderpulse {
0% {
transform: scale(0.8);
background-color: #d7b3fc;
box-shadow: 0 0 0 0 rgb(196 178 252 / 70%);
}

50% {
transform: scale(1.2);
background-color: #70198e;
box-shadow: 0 0 0 0.625em rgba(178, 212, 252, 0); /* 10px */
}

100% {
transform: scale(0.8);
background-color: #d7b3fc;
box-shadow: 0 0 0 0 rgb(196 178 252 / 70%);
}
}
/* mini loader component end */

